import{_ as e}from"./chunks/homepage.DZZjIHGg.js";import{_ as o,a,b as r,c as l,d as i}from"./chunks/output.C9LXqVDV.js";import{_ as s,o as n,c as d,ae as c}from"./chunks/framework.C00B0EYs.js";const S=JSON.parse('{"title":"快速开始","description":"Motor Sound Editor 用户首次使用指南。","frontmatter":{"title":"快速开始","description":"Motor Sound Editor 用户首次使用指南。"},"headers":[],"relativePath":"zh/docs/guide/getting-started.md","filePath":"zh/docs/guide/getting-started.md"}'),g={name:"zh/docs/guide/getting-started.md"};function h(u,t,p,m,_,f){return n(),d("div",null,[...t[0]||(t[0]=[c('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>Motor Sound Editor 面向希望在可视化编辑器中创作分层电机音效的用户，而不是手工维护原始模拟器表格。当前版本重点覆盖桌面应用里已经落地的三类核心流程：项目创作、实时预览与导出打包。</p><p><img src="'+e+'" alt="Motor Sound Editor 首页"></p><h2 id="_1-准备工作" tabindex="-1">1. 准备工作 <a class="header-anchor" href="#_1-准备工作" aria-label="Permalink to &quot;1. 准备工作&quot;">​</a></h2><h3 id="操作系统要求" tabindex="-1">操作系统要求 <a class="header-anchor" href="#操作系统要求" aria-label="Permalink to &quot;操作系统要求&quot;">​</a></h3><p><strong>Windows</strong> 是目前软件的主要支持平台。</p><h3 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h3><ul><li><strong>获取软件</strong>：你可以直接通过<a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/Motor.Sound.Editor_1.0.0_x64-setup.exe" target="_blank" rel="noreferrer">这个安装包链接</a>下载当前 Windows 安装程序。</li><li><strong>快速安装</strong>：下载完成后，运行安装程序即可。无需额外安装运行库，Tauri 所需组件已随应用打包。</li></ul><h3 id="示例文件" tabindex="-1">示例文件 <a class="header-anchor" href="#示例文件" aria-label="Permalink to &quot;示例文件&quot;">​</a></h3><p>如果你想先拿现成的 <code>.msep</code> 工程熟悉编辑器，可以直接下载这些示例：</p><ul><li><a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/caf_train_sound.msep" target="_blank" rel="noreferrer">caf_train_sound.msep</a> — 贡献者：lx9702</li><li><a href="https://github.com/xiangao0904/Motor-Sound-Editor/releases/download/v1.0.0/class323.msep" target="_blank" rel="noreferrer">class323.msep</a> — 贡献者：K.L1</li></ul><h3 id="数据与素材" tabindex="-1">数据与素材 <a class="header-anchor" href="#数据与素材" aria-label="Permalink to &quot;数据与素材&quot;">​</a></h3><ul><li><strong>素材</strong>：至少准备一段电机音源文件，支持 <code>.wav</code> 或 <code>.ogg</code>。</li><li><strong>参数</strong>：准备车辆的基础性能参数，例如最高时速、加速度和制动减速度。</li></ul><h2 id="_2-核心工作流" tabindex="-1">2. 核心工作流 <a class="header-anchor" href="#_2-核心工作流" aria-label="Permalink to &quot;2. 核心工作流&quot;">​</a></h2><p>你可以通过以下 6 个步骤快速体验软件的核心功能：</p><h3 id="第一步-创建项目" tabindex="-1">第一步：创建项目 <a class="header-anchor" href="#第一步-创建项目" aria-label="Permalink to &quot;第一步：创建项目&quot;">​</a></h3><p><img src="'+o+'" alt="新建文件"></p><ol><li>启动应用，在首页点击 <strong>New Project</strong>。</li><li>输入项目名称，例如 <code>MyTrainMotor</code>。</li><li>设定 <strong>Max Speed</strong> 和 <strong>Acceleration</strong> 等默认参数。</li><li>确认后进入编辑器。</li></ol><h3 id="第二步-管理轨道并导入音频" tabindex="-1">第二步：管理轨道并导入音频 <a class="header-anchor" href="#第二步-管理轨道并导入音频" aria-label="Permalink to &quot;第二步：管理轨道并导入音频&quot;">​</a></h3><p><img src="'+a+'" alt="导入音频"></p><ol><li>在 <strong>Track Layers</strong> 面板中，确保当前有一条激活轨道。</li><li>在 <strong>Track Details</strong> 区域点击文件选择图标。</li><li>选择 <code>.wav</code> 或 <code>.ogg</code> 音频文件。</li></ol><h3 id="第三步-绘制音高与音量曲线" tabindex="-1">第三步：绘制音高与音量曲线 <a class="header-anchor" href="#第三步-绘制音高与音量曲线" aria-label="Permalink to &quot;第三步：绘制音高与音量曲线&quot;">​</a></h3><p><img src="'+r+'" alt="绘制曲线"></p><ol><li>在工具栏中切换到 <strong>Keyframe</strong> 模式。</li><li>在图表中为 <strong>Traction Pitch</strong> 和 <strong>Traction Volume</strong> 添加关键帧，左键添加，右键删除。</li><li>如需精细调整，可以切换到 <strong>Move</strong> 模式拖动关键帧，或在 <strong>List Editor</strong> 中直接输入数值。</li></ol><h3 id="第四步-实时预览" tabindex="-1">第四步：实时预览 <a class="header-anchor" href="#第四步-实时预览" aria-label="Permalink to &quot;第四步：实时预览&quot;">​</a></h3><p><img src="'+l+'" alt="实时预览"></p><ol><li>按下 <code>Space</code> 开始播放音频。</li><li>使用 <code>W</code> 向牵引方向切换状态，使用 <code>S</code> 向制动方向切换状态。</li><li>修改 <strong>Current Speed</strong>，或切换到 <strong>Select</strong> 模式后点击图表空白区域，快速调整试听速度。</li></ol><h3 id="第五步-保存项目" tabindex="-1">第五步：保存项目 <a class="header-anchor" href="#第五步-保存项目" aria-label="Permalink to &quot;第五步：保存项目&quot;">​</a></h3><ul><li>按下 <code>Ctrl+S</code> 将项目保存为 <code>.msep</code>。</li><li><code>.msep</code> 是软件的专属工程格式，会将项目设置、曲线数据和音频素材一起打包保存，便于移动与继续编辑。</li></ul><h3 id="第六步-导出-bve-压缩包" tabindex="-1">第六步：导出 BVE 压缩包 <a class="header-anchor" href="#第六步-导出-bve-压缩包" aria-label="Permalink to &quot;第六步：导出 BVE 压缩包&quot;">​</a></h3><p><img src="'+i+'" alt="导出"></p><ol><li>点击工具栏或菜单中的 <strong>Export</strong>。</li><li>在弹出的对话框中选择 <strong>BVE</strong>。</li><li>选择采样率，通常推荐 <code>44100 Hz</code>。</li><li>软件会生成一个 <code>.zip</code> 压缩包，其中包含 BVE 所需的 <code>vehicle.txt</code>、<code>motornoise.txt</code> 和转换后的 WAV 音频。</li></ol><h2 id="_3-常用快捷键" tabindex="-1">3. 常用快捷键 <a class="header-anchor" href="#_3-常用快捷键" aria-label="Permalink to &quot;3. 常用快捷键&quot;">​</a></h2><p>熟练使用快捷键可以明显提升编辑效率：</p><table tabindex="0"><thead><tr><th style="text-align:left;">快捷键</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Space</strong></td><td style="text-align:left;">播放 / 暂停预览</td></tr><tr><td style="text-align:left;"><strong>W</strong></td><td style="text-align:left;">向牵引方向切换状态</td></tr><tr><td style="text-align:left;"><strong>S</strong></td><td style="text-align:left;">向制动方向切换状态</td></tr><tr><td style="text-align:left;"><strong>Ctrl+S</strong></td><td style="text-align:left;">保存项目</td></tr><tr><td style="text-align:left;"><strong>Ctrl+Z / Ctrl+Y</strong></td><td style="text-align:left;">撤销 / 重做</td></tr><tr><td style="text-align:left;"><strong>Delete</strong></td><td style="text-align:left;">删除选中的关键帧</td></tr></tbody></table>',35)])])}const k=s(g,[["render",h]]);export{S as __pageData,k as default};
